    if state.branch_name.startswith(PLANNED_PR_TITLE_PREFIX):
        return state

    if not impl_context_exists(state.repo_root):
        return state

    if not ctx.git.status.has_tracked_files(state.repo_root, ".erk/impl-context"):
        return state

